// EDIT: your NAICS codes and lookback window
const NAICS = ['561720'];
const DAYS = 2;
const fmt = d => `${String(d.getMonth()+1).padStart(2,'0')}/${String(d.getDate()).padStart(2,'0')}/${d.getFullYear()}`;
const to = new Date();
const from = new Date(Date.now() - DAYS * 86400000);
return NAICS.map(code => ({ json: { code, postedFrom: fmt(from), postedTo: fmt(to) } }));

const seen = new Set();
const leads = [];
for (const item of $input.all()) {
  for (const o of item.json.opportunitiesData || []) {
    const key = o.solicitationNumber || o.noticeId;
    if (seen.has(key)) continue;
    seen.add(key);
    const sa = String(o.typeOfSetAside || '');
    // keep open or small-business-friendly set-asides only
    if (sa && !/SBA|SBP|8A|HZC|SDVOSBC|WOSB/i.test(sa)) continue;
    leads.push({ title: o.title, sol: key, type: o.type, setAside: sa || 'none', naics: o.naicsCode, agency: o.fullParentPathName, due: o.responseDeadLine, link: o.uiLink });
  }
}
return [{ json: { count: leads.length, leads: leads.slice(0, 40) } }];

const txt = ($json.content || []).filter(b => b.type === 'text').map(b => b.text).join('
');
const count = $('Filter leads').first().json.count;
return [{ json: { count, text: '🏛️ SAM scout · ' + count + ' leads today

' + txt } }];
